import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';
import { useAuth } from '../../context/AuthContext';

const SEMESTERS = [1,2,3,4,5,6,7,8];

async function loadXLSX() {
  if (window.XLSX) return window.XLSX;
  await new Promise((res,rej) => { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; s.onload=res; s.onerror=rej; document.head.appendChild(s); });
  return window.XLSX;
}

async function exportExcel(sheets, filename) {
  const XLSX = await loadXLSX();
  const wb = XLSX.utils.book_new();
  sheets.forEach(({ name, data }) => {
    const ws = XLSX.utils.aoa_to_sheet(data);
    ws['!cols'] = data[0]?.map((_,ci)=>({ wch:Math.max(...data.map(r=>String(r[ci]??'').length),10) }));
    XLSX.utils.book_append_sheet(wb, ws, name.slice(0,31));
  });
  XLSX.writeFile(wb, filename);
}

async function loadJsPDF() {
  if (window.jspdf) return window.jspdf.jsPDF;
  await new Promise((res,rej) => { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js'; s.onload=res; s.onerror=rej; document.head.appendChild(s); });
  await new Promise((res,rej) => { const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.31/jspdf.plugin.autotable.min.js'; s.onload=res; s.onerror=rej; document.head.appendChild(s); });
  return window.jspdf.jsPDF;
}

async function exportPDF(title, subtitle, head, body, filename) {
  const JsPDF = await loadJsPDF();
  const doc = new JsPDF({ orientation:'landscape' });
  doc.setFontSize(16); doc.setFont('helvetica','bold');
  doc.text('VEMU Institute of Technology', doc.internal.pageSize.width/2, 15, { align:'center' });
  doc.setFontSize(12); doc.setFont('helvetica','normal');
  doc.text(title, doc.internal.pageSize.width/2, 23, { align:'center' });
  doc.setFontSize(10);
  doc.text(subtitle, doc.internal.pageSize.width/2, 30, { align:'center' });
  doc.text(`Generated: ${new Date().toLocaleDateString('en-IN')}`, doc.internal.pageSize.width/2, 36, { align:'center' });
  doc.autoTable({ startY:42, head:[head], body, styles:{fontSize:8,cellPadding:2}, headStyles:{fillColor:[26,86,219],textColor:255,fontStyle:'bold'}, alternateRowStyles:{fillColor:[241,245,249]}, margin:{left:10,right:10} });
  doc.save(filename);
}

export default function HodReports() {
  const { user } = useAuth();
  const deptName = user?.department?.name || 'Department';
  const deptCode = user?.department?.code || '';
  const [loading, setLoading] = useState(false);
  const [selSem,  setSelSem]  = useState('');
  const [selSec,  setSelSec]  = useState('');
  const [sections,setSections]= useState([]);

  useEffect(() => {
    axios.get('/api/hod/sections').then(r => setSections(r.data.sections||[])).catch(()=>{});
  }, []);

  const wrap = async fn => { setLoading(true); try { await fn(); } catch(e) { toast.error('Export failed: '+e.message); } finally { setLoading(false); } };

  // â”€â”€ Full dept report â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const excelDeptFull = () => wrap(async () => {
    const [studR, facR, subjR, marksR] = await Promise.all([
      axios.get('/api/hod/students'),
      axios.get('/api/hod/faculty'),
      axios.get('/api/hod/subjects'),
      axios.get('/api/hod/marks'),
    ]);
    const sheets = [
      { name:'Students', data:[
        [`${deptName} â€” Students`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Name','Roll No','Semester','Section'],
        ...studR.data.students.map((s,i)=>[i+1,s.name,s.rollNumber,`Sem ${s.semester}`,s.section||'â€”'])
      ]},
      { name:'Faculty', data:[
        [`${deptName} â€” Faculty`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Name','Roll No','Department'],
        ...facR.data.faculty.map((f,i)=>[i+1,f.name,f.rollNumber,deptName])
      ]},
      { name:'Subjects', data:[
        [`${deptName} â€” Subjects`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Subject','Code','Semester','Credits','Max Marks'],
        ...subjR.data.subjects.map((s,i)=>[i+1,s.name,s.code,`Sem ${s.semester}`,s.credits,s.maxMidMarks])
      ]},
      { name:'All Marks', data:[
        [`${deptName} â€” All Marks`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Student','Roll No','Sem','Sec','Subject','Exam','Asgn/5','SHA/10','Q-Half/15','Total/30','Faculty','Status'],
        ...marksR.data.marks.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.semester,m.student?.section||'â€”',m.subject?.name||'â€”',m.midExam,m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.faculty?.name||'â€”',m.status])
      ]}
    ];
    await exportExcel(sheets, `VEMU_${deptCode}_FullReport.xlsx`);
    toast.success('Department report Excel downloaded!');
  });

  const pdfDeptFull = () => wrap(async () => {
    const marksR = await axios.get('/api/hod/marks');
    await exportPDF(`${deptName} â€” Full Marks Report`, 'Department Level',
      ['#','Student','Roll No','Sem','Sec','Subject','Exam','Total/30','Faculty','Status'],
      marksR.data.marks.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.semester,m.student?.section||'â€”',m.subject?.name||'â€”',m.midExam,m.totalMarks,m.faculty?.name||'â€”',m.status]),
      `VEMU_${deptCode}_Marks.pdf`);
    toast.success('PDF downloaded!');
  });

  // â”€â”€ Class-wise (semester) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const excelClassWise = () => wrap(async () => {
    if (!selSem) return toast.error('Select a semester');
    const [marksR, studR] = await Promise.all([
      axios.get('/api/hod/marks', { params:{ semester:selSem } }),
      axios.get('/api/hod/students', { params:{ semester:selSem, ...(selSec?{section:selSec}:{}) } }),
    ]);
    const mid1 = marksR.data.marks.filter(m=>m.midExam==='Mid-1' && (!selSec || m.student?.section===selSec));
    const mid2 = marksR.data.marks.filter(m=>m.midExam==='Mid-2' && (!selSec || m.student?.section===selSec));
    const label = selSec ? `Sem${selSem}_Sec${selSec}` : `Sem${selSem}`;
    const sheets = [
      { name:`${label} Mid-1`, data:[
        [`${deptName} â€” Semester ${selSem}${selSec?' Section '+selSec:''} â€” Mid-1`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Q-Half/15','Total/30','Faculty','Status'],
        ...mid1.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.student?.section||'â€”',m.subject?.name||'â€”',m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.faculty?.name||'â€”',m.status])
      ]},
      { name:`${label} Mid-2`, data:[
        [`${deptName} â€” Semester ${selSem}${selSec?' Section '+selSec:''} â€” Mid-2`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Q-Half/15','Total/30','Faculty','Status'],
        ...mid2.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.student?.section||'â€”',m.subject?.name||'â€”',m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.faculty?.name||'â€”',m.status])
      ]}
    ];
    await exportExcel(sheets, `VEMU_${deptCode}_${label}_Marks.xlsx`);
    toast.success('Class-wise report downloaded!');
  });

  const pdfClassWise = () => wrap(async () => {
    if (!selSem) return toast.error('Select a semester');
    const marksR = await axios.get('/api/hod/marks', { params:{ semester:selSem } });
    const filtered = marksR.data.marks.filter(m => !selSec || m.student?.section===selSec);
    await exportPDF(
      `${deptName} â€” Semester ${selSem}${selSec?' Section '+selSec:''} Marks`,
      'Class-wise Report',
      ['#','Student','Roll No','Sec','Subject','Exam','Asgn/5','SHA/10','Q-Half/15','Total/30','Status'],
      filtered.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.student?.section||'â€”',m.subject?.name||'â€”',m.midExam,m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status]),
      `VEMU_${deptCode}_Sem${selSem}${selSec?'_Sec'+selSec:''}_Marks.pdf`);
    toast.success('PDF downloaded!');
  });

  // â”€â”€ Subject-wise â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const excelSubjectWise = () => wrap(async () => {
    if (!selSem) return toast.error('Select a semester first');
    const [subjR, marksR] = await Promise.all([
      axios.get('/api/hod/subjects', { params:{ semester:selSem } }),
      axios.get('/api/hod/marks', { params:{ semester:selSem } }),
    ]);
    const sheets = subjR.data.subjects.map(subj => {
      const sMarks = marksR.data.marks.filter(m=>m.subject?._id===subj._id);
      return {
        name: subj.code.slice(0,31),
        data: [
          [`Subject: ${subj.name} (${subj.code}) â€” Semester ${selSem}`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
          ['#','Student','Roll No','Section','Exam','Asgn/5','SHA/10','Q-Half/15','Total/30','Status'],
          ...sMarks.map((m,i)=>[i+1,m.student?.name||'â€”',m.student?.rollNumber||'â€”',m.student?.section||'â€”',m.midExam,m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status])
        ]
      };
    });
    if (!sheets.length) return toast.error('No subjects found');
    await exportExcel(sheets, `VEMU_${deptCode}_Sem${selSem}_SubjectWise.xlsx`);
    toast.success(`Subject-wise report (${sheets.length} sheets) downloaded!`);
  });

  return (
    <div>
      <div className="page-header">
        <div><div className="page-title">đź“‹ Reports</div><div className="page-subtitle">{deptName} â€” Generate department-level reports</div></div>
      </div>

      {/* â”€â”€ Full Dept â”€â”€ */}
      <div className="card" style={{ marginBottom:20 }}>
        <div className="card-header"><span className="card-title">đźŹ˘ Full Department Report</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)',fontSize:13,marginBottom:14 }}>Complete report: Students + Faculty + Subjects + All Marks (4 sheets)</p>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success" onClick={excelDeptFull} disabled={loading}>đź“Š Download Excel (4 Sheets)</button>
            <button className="btn btn-danger"  onClick={pdfDeptFull}   disabled={loading}>đź“„ Download PDF</button>
          </div>
        </div>
      </div>

      {/* â”€â”€ Class-wise â”€â”€ */}
      <div className="card" style={{ marginBottom:20 }}>
        <div className="card-header"><span className="card-title">đź“š Class-wise Report (Semester + Section)</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)',fontSize:13,marginBottom:12 }}>Mid-1 and Mid-2 marks for a specific class. Section is optional.</p>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap', marginBottom:14 }}>
            <select className="form-select" style={{ width:160 }} value={selSem} onChange={e=>setSelSem(e.target.value)}>
              <option value="">Select Semester</option>
              {SEMESTERS.map(s=><option key={s} value={s}>Semester {s}</option>)}
            </select>
            <select className="form-select" style={{ width:150 }} value={selSec} onChange={e=>setSelSec(e.target.value)}>
              <option value="">All Sections</option>
              {sections.filter(s=>!selSem||s.semester===Number(selSem)).map(s=><option key={s._id} value={s.name}>Section {s.name}</option>)}
            </select>
          </div>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success btn-sm" onClick={excelClassWise}   disabled={loading||!selSem}>đź“Š Class Marks Excel (Mid-1 + Mid-2)</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfClassWise}     disabled={loading||!selSem}>đź“„ Class Marks PDF</button>
            <button className="btn btn-primary btn-sm" onClick={excelSubjectWise} disabled={loading||!selSem}>đź“Š Subject-wise Excel (one sheet per subject)</button>
          </div>
        </div>
      </div>

      {loading && <div style={{ textAlign:'center',padding:20,color:'var(--text-muted)',fontSize:13 }}>âŹł Generating report, please wait...</div>}
    </div>
  );
}
